class TaskOrchestrator {
  async execute() {
    // 1. 建立元件
    const uploader = new StreamDataDriver()
    const backupBuilder = new BackupFileBuilder()

    // 2. 組裝 (註冊觀察者)
    uploader.addListener(backupBuilder)

    try {
      // 3. 執行主流程 (PrimaryAPI 上傳)
      await uploader.execute()

      // 4. 控制流程：只有 PrimaryAPI 成功，才繼續 BackupService
      // 從 Builder 取得準備好的暫存檔路徑
      const result = await backupBuilder.finish()

      if (result.count > 0) {
        await backupUploader.execute(result.filePath)
      }
    }
    catch (err) {
      // 5. 統一錯誤處理與資源清理
      backupBuilder.cleanup()
      throw err
    }
  }
}

function validateKeywordsFormat(input: string): string | null {
  const trimmedInput = input.trim()

  // 檢查是否為空
  if (!trimmedInput) {
    return '請輸入關鍵字'
  }

  // 檢查括號是否配對
  let parenthesesCount = 0
  for (const char of trimmedInput) {
    if (char === '(')
      parenthesesCount++
    if (char === ')')
      parenthesesCount--
    if (parenthesesCount < 0)
      return '括號配對錯誤'
  }
  if (parenthesesCount !== 0)
    return '括號配對錯誤'

  // 檢查邏輯運算子格式（必須為大寫）
  if (/\b(?:and|not|or)\b/i.test(trimmedInput)) {
    return '邏輯運算子必須使用大寫：AND、NOT、OR'
  }

  // 檢查運算子前後是否有適當的空白
  if (/(?:^|\S)\b(?:AND|NOT|OR)\b(?:\S|$)/.test(trimmedInput)) {
    return '邏輯運算子前後必須有空白間隔'
  }

  // 檢查 AND/OR 不能緊接在左括號後面
  if (/\(\s*(?:AND|OR)\b/.test(trimmedInput)) {
    return 'AND/OR 運算子前面必須有運算元'
  }

  // ... 還有更多規則
}

