        // left = 前一個 frozen sibling 的「當下 DOM 寬度」+ 它的 inline left
        pos = getOuterWidth(prev) + parseFloat(prev.style.left || 0);
      }
      this.styleObject.left = pos + 'px';
    }
  }
}

